mapper.select:
SELECT MR.RECORD_ID AS recordId, MR.HOSPITAL_ID AS hospitalId, MR.RESV_ID AS resvId, MR.PET_ID AS petId, MR.MEMBER_NO AS memberNo, MR.VISIT_DATE AS visitDate, MR.SYMPTOMS AS symptoms, MR.DIAGNOSIS AS diagnosis, MR.PRESCRIPTION AS prescription, MR.MEMO AS memo, MR.VET_NAME AS vetName, MR.REG_DATE AS regDate, P.PET_NAME AS petName, P.SPECIES AS petSpecies, P.BREED AS petBreed, P.AGE AS petAge, H.NAME AS hospitalName FROM TB_MEDICAL_RECORD MR JOIN TB_PET P ON P.PET_ID = MR.PET_ID JOIN TB_HOSPITAL H ON H.HOSPITAL_ID = MR.HOSPITAL_ID WHERE MR.MEMBER_NO = #{memberNo}
AND MR.PET_ID = #{petId}
ORDER BY MR.VISIT_DATE DESC, MR.RECORD_ID DESC
